@import '../../utils/typography.css';

:host {
  box-sizing: border-box;
  max-width: 100%;
  min-width: 0;
  margin: 0;
  padding: 0;
  border: 0;
  font-family: var(--typography-font-family);
}

:host(.ds-text--inline-box) {
  display: inline-block;
}

:host(.ds-text--block-box) {
  display: block;
  width: 100%;
}

/*
 * The host is the measurable typography box. The semantic inner element fills
 * it and inherits every text metric without adding margins, padding, or its own
 * line-height strut. One rendered line therefore measures exactly one token
 * line-height; N lines measure N × that token.
 */
.ds-text__element {
  display: block;
  box-sizing: border-box;
  min-width: 0;
  margin: 0;
  padding: 0;
  border: 0;
  font: inherit;
  line-height: inherit;
  letter-spacing: inherit;
  color: inherit;
  text-transform: inherit;
  text-align: inherit;
  text-decoration: inherit;
  font-style: inherit;
  font-variant-numeric: inherit;
  font-feature-settings: inherit;
  white-space: inherit;
  text-wrap: inherit;
  overflow-wrap: inherit;
  word-break: inherit;
}

/* ── Truncation ─────────────────────────────────────────────────────────── */

:host(.ds-text--truncate-1) {
  overflow: hidden;
}

:host(.ds-text--truncate-1) .ds-text__element {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

:host(.ds-text--truncate-2),
:host(.ds-text--truncate-3),
:host(.ds-text--truncate-4),
:host(.ds-text--truncate-5) {
  overflow: hidden;
}

:host(.ds-text--truncate-2) .ds-text__element,
:host(.ds-text--truncate-3) .ds-text__element,
:host(.ds-text--truncate-4) .ds-text__element,
:host(.ds-text--truncate-5) .ds-text__element {
  display: -webkit-box;
  -webkit-box-orient: vertical;
  overflow: hidden;
  text-overflow: ellipsis;
  word-break: break-word;
}

:host(.ds-text--truncate-2) .ds-text__element { -webkit-line-clamp: 2; }
:host(.ds-text--truncate-3) .ds-text__element { -webkit-line-clamp: 3; }
:host(.ds-text--truncate-4) .ds-text__element { -webkit-line-clamp: 4; }
:host(.ds-text--truncate-5) .ds-text__element { -webkit-line-clamp: 5; }

/* ── Wrap ───────────────────────────────────────────────────────────────── */

:host(.ds-text--nowrap),
:host(.ds-text--nowrap) .ds-text__element {
  white-space: nowrap;
  word-break: normal;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
}

:host(.ds-text--balance),
:host(.ds-text--balance) .ds-text__element { text-wrap: balance; }

:host(.ds-text--pretty),
:host(.ds-text--pretty) .ds-text__element { text-wrap: pretty; }

/* ── Color ──────────────────────────────────────────────────────────────── */

:host(.ds-text--color-primary)   { color: var(--color-foreground-primary); }
:host(.ds-text--color-secondary) { color: var(--color-foreground-secondary); }
:host(.ds-text--color-tertiary)  { color: var(--color-foreground-tertiary); }
:host(.ds-text--color-brand)     { color: var(--color-foreground-bold-brand); }
:host(.ds-text--color-negative)  { color: var(--color-foreground-bold-negative); }
:host(.ds-text--color-positive)  { color: var(--color-foreground-bold-positive); }
:host(.ds-text--color-warning)   { color: var(--color-foreground-bold-warning); }
:host(.ds-text--color-caution)   { color: var(--color-foreground-bold-caution); }
:host(.ds-text--color-ai)        { color: var(--color-foreground-bold-ai); }
:host(.ds-text--color-on-strong) { color: var(--color-foreground-on-strong-background-primary); }
:host(.ds-text--color-on-bold)   { color: var(--color-foreground-on-bold-background-primary); }
:host(.ds-text--color-inherit)   { color: inherit; }

/* ── Decorations ─────────────────────────────────────────────────────────── */

:host(.ds-text--decoration-underline) {
  text-decoration: underline;
  text-underline-offset: 2px;
  text-decoration-thickness: 1px;
}

:host(.ds-text--decoration-dotted-underline) {
  text-decoration: underline dotted;
  text-underline-offset: 2px;
  text-decoration-thickness: 1px;
}

/* ── Style ──────────────────────────────────────────────────────────────── */

:host(.ds-text--italic) { font-style: italic; }

:host(.ds-text--font-feature-tabular-nums) {
  font-variant-numeric: tabular-nums;
  font-feature-settings: 'tnum';
}

/* ── Align ──────────────────────────────────────────────────────────────── */

:host(.ds-text--align-left)   { text-align: left; }
:host(.ds-text--align-center) { text-align: center; }
:host(.ds-text--align-right)  { text-align: right; }

import { Component, Prop, h, Host } from '@stencil/core';
import { textDisplayClass, textVariantClass } from './text-utils';
import type {
  TextAlign,
  TextColor,
  TextDecoration,
  TextElement,
  TextFontFeature,
  TextVariant,
  LineTruncation,
  TextWrap,
} from './text-types';

@Component({
  tag: 'ds-text',
  styleUrl: 'Text.css',
  scoped: true,
})
export class Text {
  @Prop() variant: TextVariant = 'text-body-medium';
  /**
   * Heavier weight + tighter letter-spacing for the variant.
   * `false` (default): regular weight (caption stays medium).
   * `true`: display bold, title/caption semibold, body medium.
   */
  @Prop() emphasis: boolean = false;
  @Prop() color: TextColor | undefined;
  @Prop() decoration: TextDecoration | undefined;
  @Prop() italic: boolean = false;
  @Prop() align: TextAlign | undefined;
  @Prop() lineTruncation: LineTruncation = 'none';
  @Prop() wrap: TextWrap | undefined;
  @Prop() fontFeature: TextFontFeature = 'normal';
  @Prop() as: TextElement = 'p';
  /** Maps to `for` attribute on <label> elements. */
  @Prop() for: string | undefined;
  /** Forwarded to the inner element (e.g. aria-labelledby targets). */
  @Prop() textId: string | undefined;

  render() {
    // Polymorphic element: TSX treats a variable tag as a component, so a
    // dynamic intrinsic element name must be cast to `any` to render.
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const Tag = this.as as any;
    const isCustomColor = (c: TextColor) => typeof c === 'string' && c.startsWith('var(--');

    const cls: Record<string, boolean> = {
      'ds-text': true,
      [textDisplayClass(this.as)]: true,
      [textVariantClass(this.variant)]: true,
      'ds-text--emphasis': this.emphasis,
      'ds-text--regular': !this.emphasis,
      'ds-text--nowrap': this.wrap === 'nowrap',
      'ds-text--balance': this.wrap === 'balance',
      'ds-text--pretty': this.wrap === 'pretty',
      'ds-text--truncate-1': this.lineTruncation === 1 && this.wrap !== 'nowrap',
      'ds-text--truncate-2': this.lineTruncation === 2 && this.wrap !== 'nowrap',
      'ds-text--truncate-3': this.lineTruncation === 3 && this.wrap !== 'nowrap',
      'ds-text--truncate-4': this.lineTruncation === 4 && this.wrap !== 'nowrap',
      'ds-text--truncate-5': this.lineTruncation === 5 && this.wrap !== 'nowrap',
      'ds-text--color-primary':   this.color === 'primary',
      'ds-text--color-secondary': this.color === 'secondary',
      'ds-text--color-tertiary':  this.color === 'tertiary',
      'ds-text--color-brand':     this.color === 'brand',
      'ds-text--color-negative':  this.color === 'negative',
      'ds-text--color-positive':  this.color === 'positive',
      'ds-text--color-warning':   this.color === 'warning',
      'ds-text--color-caution':   this.color === 'caution',
      'ds-text--color-ai':        this.color === 'ai',
      'ds-text--color-on-strong': this.color === 'on-strong',
      'ds-text--color-on-bold':   this.color === 'on-bold',
      'ds-text--color-inherit':   this.color === 'inherit',
      'ds-text--decoration-underline':        this.decoration === 'underline',
      'ds-text--decoration-dotted-underline': this.decoration === 'dotted-underline',
      'ds-text--italic': this.italic,
      'ds-text--align-left':   this.align === 'left',
      'ds-text--align-center': this.align === 'center',
      'ds-text--align-right':  this.align === 'right',
      'ds-text--font-feature-tabular-nums': this.fontFeature === 'tabular-nums',
    };

    const style = this.color && isCustomColor(this.color)
      ? { color: this.color as string }
      : undefined;

    const extraProps: Record<string, string> = {};
    if (this.as === 'label' && this.for) extraProps['for'] = this.for;
    if (this.textId) extraProps['id'] = this.textId;

    return (
      <Host class={cls} style={style}>
        <Tag class="ds-text__element" {...extraProps}>
          <slot />
        </Tag>
      </Host>
    );
  }
}

export type TextVariant =
  | 'text-display-medium'
  | 'text-display-small'
  | 'text-title-large'
  | 'text-title-medium'
  | 'text-title-small'
  | 'text-body-large'
  | 'text-body-medium'
  | 'text-body-small'
  | 'text-caption';

export type TextColorToken =
  | 'primary' | 'secondary' | 'tertiary'
  | 'brand' | 'negative' | 'positive' | 'warning' | 'caution' | 'ai'
  | 'on-strong' | 'on-bold' | 'inherit';

export type TextColor = TextColorToken | `var(--${string})`;
export type TextDecoration = 'none' | 'underline' | 'dotted-underline';
export type TextAlign = 'left' | 'center' | 'right';
export type LineTruncation = 1 | 2 | 3 | 4 | 5 | 'none';
export type TextWrap = 'wrap' | 'nowrap' | 'balance' | 'pretty';
export type TextElement = 'p' | 'span' | 'div' | 'label' | 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6';
export type TextFontFeature = 'normal' | 'tabular-nums';

import type { TextElement, TextVariant } from './text-types';

/** `text-body-medium` → `ds-text--body-medium` */
export function textVariantClass(variant: TextVariant): string {
  return `ds-text--${variant.replace(/^text-/, '')}`;
}

/** Inline semantics get a measurable inline box; paragraphs/headings get a block box. */
export function textDisplayClass(element: TextElement): string {
  return element === 'span' || element === 'label'
    ? 'ds-text--inline-box'
    : 'ds-text--block-box';
}
